-- bible-text.db schema
-- Master build artifact: NOT committed (see .gitignore). Regenerated by build.py
-- from the open-data/ submodules. Contains all license tiers (including
-- 'restricted-nc' and 'unknown') -- tier filtering happens at export time,
-- not at ingestion time, so nothing here should be assumed safe to publish
-- without checking works.license_tier first.

CREATE TABLE works (
    work_id TEXT PRIMARY KEY,       -- unique per DISTRIBUTION, e.g. 'scrollmapper-KJV', 'morphhb-wlc'
    translation_code TEXT,          -- canonical short code, e.g. 'KJV' -- may repeat across work_id
                                     -- when the same nominal translation comes from multiple sources
    title TEXT,
    language TEXT,                  -- 'heb', 'grc', 'eng', etc.

    -- heritage: exactly where this distribution came from and when
    source_id TEXT,                 -- submodule name, e.g. 'scrollmapper-bible-databases'
    source_repo_url TEXT,           -- our fork URL
    source_commit TEXT,             -- submodule git commit hash at ingestion time
    ingested_at TEXT,               -- ISO date of this build

    -- licensing: verbatim as reported by the source, plus our classification
    license TEXT,                   -- verbatim string, e.g. 'Creative Commons: BY-NC-SA 4.0'
    license_tier TEXT NOT NULL,     -- 'open' | 'restricted-nc' | 'unknown' | 'quotation-only'
    attribution TEXT,
    notes TEXT                      -- e.g. caveats like the strongs/TWOT one, or classification rationale
);

CREATE TABLE verses (
    work_id TEXT NOT NULL REFERENCES works(work_id),
    book TEXT NOT NULL,             -- OSIS book code (GEN, EXO, ... MATT, ... REV)
    chapter INTEGER NOT NULL,
    verse INTEGER NOT NULL,
    text TEXT NOT NULL
);
CREATE INDEX idx_verses_ref ON verses(book, chapter, verse);
CREATE INDEX idx_verses_work ON verses(work_id);

CREATE TABLE morphology (           -- word-by-word tags on original-language verses
    work_id TEXT NOT NULL REFERENCES works(work_id),
    book TEXT NOT NULL,
    chapter INTEGER NOT NULL,
    verse INTEGER NOT NULL,
    word_position INTEGER NOT NULL,
    surface_form TEXT,
    strongs_id TEXT,                -- bare numeric, no G/H prefix; occasionally compound ('1537+4053')
                                     -- for a single word covered by multiple Strong's numbers -- lookups
                                     -- on a specific number need to account for that, not just '='
    morph_code TEXT,
    cantillation_level TEXT,
    lemma TEXT,                     -- dictionary form, only populated by macula-* work_ids so far
    gloss TEXT,                     -- short English gloss, only populated by macula-* work_ids so far
    domain_code TEXT                -- semantic domain code: Louw-Nida 'NN.NN' (Greek) or SDBH
                                     -- lexdomain/contextualdomain (Hebrew); only macula-* work_ids so far
);
CREATE INDEX idx_morph_ref ON morphology(book, chapter, verse);
CREATE INDEX idx_morph_strongs ON morphology(strongs_id);
CREATE INDEX idx_morph_domain ON morphology(domain_code);

CREATE TABLE literary_units (       -- paragraph/pericope boundaries, keyed to the Masoretic text's
                                     -- own markers (samekh/pe), not modern chapter divisions
    work_id TEXT NOT NULL REFERENCES works(work_id),
    book TEXT NOT NULL,
    unit_type TEXT NOT NULL,        -- 'paragraph' | 'pericope'
    start_chapter INTEGER NOT NULL, start_verse INTEGER NOT NULL,
    end_chapter INTEGER NOT NULL, end_verse INTEGER NOT NULL
);
CREATE INDEX idx_units_ref ON literary_units(book, start_chapter, start_verse);

CREATE TABLE notes (                -- edition-bundled translator/study notes
    work_id TEXT NOT NULL REFERENCES works(work_id),
    book TEXT NOT NULL,
    chapter INTEGER NOT NULL,
    verse INTEGER NOT NULL,
    note_type TEXT,                 -- 'translator' | 'study' | other
    text TEXT NOT NULL
);
CREATE INDEX idx_notes_ref ON notes(book, chapter, verse);

CREATE TABLE cross_references (     -- verse-to-verse, translation-independent
    work_id TEXT NOT NULL REFERENCES works(work_id),
    from_book TEXT NOT NULL, from_chapter INTEGER NOT NULL, from_verse INTEGER NOT NULL,
    to_book TEXT NOT NULL, to_chapter INTEGER NOT NULL,
    to_verse_start INTEGER NOT NULL, to_verse_end INTEGER NOT NULL,
    votes INTEGER
);
CREATE INDEX idx_xref_from ON cross_references(from_book, from_chapter, from_verse);
